import java.io.*;
import java.util.*;

public class XSSFixedCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize and escape user input to prevent XSS
        String sanitizedInput = escapeHtml(userInput);

        System.out.println("Hello, " + sanitizedInput + "!"); // Safe line

        scanner.close();
    }

    // Method to escape HTML special characters
    private static String escapeHtml(String input) {
        return input.replaceAll("&", "&amp;")
                     .replaceAll("<", "&lt;")
                     .replaceAll(">", "&gt;")
                     .replaceAll("\"", "&quot;")
                     .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
